10	void set_type_tile_to_empty(const int x, const int y, vtr::NdMatrix<t_grid_tile, 3>& grid) {
11	    t_physical_tile_type_ptr type = grid[0][x][y].type;
12	    const int width_offset = grid[0][x][y].width_offset;
13	    const int height_offset = grid[0][x][y].height_offset;
14	    const int x_anchor = x - width_offset;
15	    const int y_anchor = y - height_offset;
16	
17	    for (int i = x_anchor; i < x_anchor + type->width; i++) {
18	        for (int j = y_anchor; j < y_anchor + type->height; j++) {
19	            if (grid[0][i][j].type == type && grid[0][i][j].width_offset == i - x_anchor && grid[0][i][j].height_offset == j - y_anchor) {
20	                grid[0][i][j].type = g_vpr_ctx.device().EMPTY_PHYSICAL_TILE_TYPE;
21	                grid[0][i][j].width_offset = 0;
22	                grid[0][i][j].height_offset = 0;
23	            }
24	        }
25	    }
26	}
