28	void set_tile_type_at_loc(const int x_anchor, const int y_anchor, vtr::NdMatrix<t_grid_tile, 3>& grid, const t_physical_tile_type& tile_type) {
29	
30	    for (int i = x_anchor; i < x_anchor + tile_type.width; i++) {
31	        for (int j = y_anchor; j < y_anchor + tile_type.height; j++) {
32	            if (grid[0][i][j].type != g_vpr_ctx.device().EMPTY_PHYSICAL_TILE_TYPE) {
33	                set_type_tile_to_empty(i, j, grid);
34	            }
35	            grid[0][i][j].type = &tile_type;
36	            grid[0][i][j].width_offset = i - x_anchor;
37	            grid[0][i][j].height_offset = j - y_anchor;
38	        }
39	    }
40	}
